-- 4. cash_positioning_runs — executor target (one row per approved position_cash action)
create table cash_positioning_runs (
  id uuid primary key default gen_random_uuid(),
  org_id uuid not null references organizations(id) on delete cascade,
  payload_id uuid not null references inbound_payloads(id) on delete cascade,
  proposed_action_id uuid references proposed_actions(id),
  as_of_date text not null,
  total_cash_balance numeric not null default 0,
  cash_by_account jsonb not null,
  inflows_next_7d numeric not null default 0,
  outflows_next_7d numeric not null default 0,
  inflows_next_30d numeric not null default 0,
  outflows_next_30d numeric not null default 0,
  projected_balance_7d numeric not null default 0,
  projected_balance_30d numeric not null default 0,
  minimum_operating_cash numeric,
  cash_cushion_days numeric,
  liquidity_status text not null,
  alerts jsonb not null,
  created_at timestamptz not null default now()
);
create index idx_cash_positioning_runs_org_id on cash_positioning_runs(org_id);
create index idx_cash_positioning_runs_payload_id on cash_positioning_runs(payload_id);

alter table cash_positioning_runs enable row level security;
create policy tenant_isolation_cash_positioning_runs on cash_positioning_runs
  using (org_id = current_setting('app.current_org_id', true)::uuid)
  with check (org_id = current_setting('app.current_org_id', true)::uuid);
